        // GET: Product/Details/5
        public ActionResult Details(int id)
        {
            // Fetch product details (optional, but good for a product page)
            var product = _context.Products.FirstOrDefault(p => p.Id == id);
            if (product == null)
            {
                return HttpNotFound();
            }

            // Fetch reviews for the product
            var reviews = _context.Reviews
                                  .Where(r => r.ProductId == id)
                                  .OrderByDescending(r => r.SubmissionDate)
                                  .ToList();

            var viewModel = new ProductDetailsViewModel
            {
                Product = product,
                Reviews = reviews.Select(r => new ReviewViewModel
                {
                    ReviewId = r.Id,
                    UserName = r.UserName, // Or fetch from User table if UserId is stored
                    Rating = r.Rating,
                    Comment = ProcessReviewComment(r.Comment), // Process for formatting
                    SubmissionDate = r.SubmissionDate
                }).ToList()
            };

            return View(viewModel);
        }

        // Helper method to process review comments for basic formatting
        private string ProcessReviewComment(string comment)
        {
            if (string.IsNullOrWhiteSpace(comment))
            {
                return string.Empty;
            }

            // Replace **text** with <strong>text</strong>
            comment = Regex.Replace(comment, @"\*\*(.*?)\*\*", "<strong>$1</strong>");

            // Replace *text* with <em>text</em>
            comment = Regex.Replace(comment, @"\*(.*?)\*", "<em>$1</em>");

            // Basic HTML encoding to prevent XSS for other characters
            // Note: MvcHtmlString.Create will mark the string as safe,
            // but we need to ensure *only* our allowed tags are present.
            // A more robust solution might involve a dedicated sanitization library.
            comment = HttpUtility.HtmlEncode(comment);

            // Now, decode only the tags we explicitly allowed
            comment = comment.Replace("&lt;strong&gt;", "<strong>");
            comment = comment.Replace("&lt;/strong&gt;", "</strong>");
            comment = comment.Replace("&lt;em&gt;", "<em>");
            comment = comment.Replace("&lt;/em&gt;", "</em>");
            
            return comment;
        }

